import{_ as d,o as r,c as a,a2 as h}from"./chunks/framework.B72_uj9U.js";const F=JSON.parse('{"title":"食品农业行业供应商自评问卷（SAQ-FOOD-001）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/industry/food/saq.md","filePath":"zh/industry/food/saq.md"}'),e={name:"zh/industry/food/saq.md"};function o(_,t,l,n,s,b){return r(),a("div",null,[...t[0]||(t[0]=[h('<h1 id="食品农业行业供应商自评问卷-saq-food-001" tabindex="-1">食品农业行业供应商自评问卷（SAQ-FOOD-001） <a class="header-anchor" href="#食品农业行业供应商自评问卷-saq-food-001" aria-label="Permalink to &quot;食品农业行业供应商自评问卷（SAQ-FOOD-001）&quot;">​</a></h1><blockquote><p><strong>版本：</strong> 2025年版 · <strong>适用范围：</strong> 食品加工厂、农场/种植园、农业原料供应商、冷链物流提供商</p></blockquote><hr><p><strong>供应商信息</strong></p><table tabindex="0"><thead><tr><th>字段</th><th>填写</th></tr></thead><tbody><tr><td>企业法人名称</td><td></td></tr><tr><td>生产/农场地址（含GPS坐标，如适用）</td><td></td></tr><tr><td>主要产品/商品</td><td></td></tr><tr><td>年产量/收购量</td><td></td></tr><tr><td>食品安全认证（ISO 22000 / FSSC / BRCGS 等）</td><td></td></tr><tr><td>是否涉及EUDR覆盖商品（大豆/棕榈油/可可/咖啡等）</td><td></td></tr><tr><td>填表人 / 职务 / 日期</td><td></td></tr></tbody></table><hr><h2 id="模块-f1-食品安全管理" tabindex="-1">模块 F1　食品安全管理 <a class="header-anchor" href="#模块-f1-食品安全管理" aria-label="Permalink to &quot;模块 F1　食品安全管理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>F1.1</td><td>是否建立并实施了HACCP（危害分析与关键控制点）体系？</td><td></td><td></td><td></td><td></td></tr><tr><td>F1.2</td><td>HACCP计划是否经过外部认证机构验证？</td><td></td><td></td><td></td><td></td></tr><tr><td>F1.3</td><td>过去5年内是否有产品召回记录？</td><td></td><td></td><td></td><td></td></tr><tr><td>F1.4</td><td>是否有食品欺诈（掺假）预防计划（VACCP/TACCP）？</td><td></td><td></td><td></td><td></td></tr><tr><td>F1.5</td><td>生产设施的清洁卫生是否有书面程序和执行记录？</td><td></td><td></td><td></td><td></td></tr><tr><td>F1.6</td><td>是否对成品进行微生物和农药残留检测，频率符合买方要求？</td><td></td><td></td><td></td><td></td></tr><tr><td>F1.7</td><td>是否有产品追溯系统，能在4小时内追溯批次来源和去向？</td><td></td><td></td><td></td><td></td></tr><tr><td>F1.8</td><td>过敏原管理是否有专项程序（交叉污染控制、标签准确性）？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="模块-f2-农业劳工-种植园-农场适用" tabindex="-1">模块 F2　农业劳工（种植园/农场适用） <a class="header-anchor" href="#模块-f2-农业劳工-种植园-农场适用" aria-label="Permalink to &quot;模块 F2　农业劳工（种植园/农场适用）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>F2.1</td><td>是否使用季节性临时工？如有，请说明用工规模和招募方式</td><td></td><td></td><td></td><td></td></tr><tr><td>F2.2</td><td>是否向工人收取招募费或提供债务性&quot;预付款&quot;？</td><td></td><td></td><td></td><td></td></tr><tr><td>F2.3</td><td>儿童是否被允许在农场/种植园内工作（包括协助家长的非正式情况）？</td><td></td><td></td><td></td><td></td></tr><tr><td>F2.4</td><td>如使用移民/外籍劳工，是否核验其合法工作资格？</td><td></td><td></td><td></td><td></td></tr><tr><td>F2.5</td><td>工人是否被提供基本生活设施（住宿、饮用水、卫生设施）并符合当地标准？</td><td></td><td></td><td></td><td></td></tr><tr><td>F2.6</td><td>是否向农药施用工人提供适当的个人防护设备（PPE），并进行培训？</td><td></td><td></td><td></td><td></td></tr><tr><td>F2.7</td><td>工人是否了解其工资计算方式，并能对账单提出异议？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="模块-f3-eudr合规-欧盟毁林法规-2024年起" tabindex="-1">模块 F3　EUDR合规（欧盟毁林法规，2024年起） <a class="header-anchor" href="#模块-f3-eudr合规-欧盟毁林法规-2024年起" aria-label="Permalink to &quot;模块 F3　EUDR合规（欧盟毁林法规，2024年起）&quot;">​</a></h2><p><em>仅适用于大豆、棕榈油、可可、咖啡、牛肉/皮革、木材、橡胶及其衍生产品。</em></p><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>F3.1</td><td>贵公司供应的商品是否属于EUDR监管范畴？</td><td></td><td></td><td></td><td></td></tr><tr><td>F3.2</td><td>是否能提供农场/生产地块的GPS多边形坐标，精确至地块级别？</td><td></td><td></td><td></td><td></td></tr><tr><td>F3.3</td><td>这些地块是否可证明在2020年12月31日前已转化为农业用地（非新开荒）？</td><td></td><td></td><td></td><td></td></tr><tr><td>F3.4</td><td>是否持有合法的土地使用权/租赁协议，且无与当地社区的土地纠纷记录？</td><td></td><td></td><td></td><td></td></tr><tr><td>F3.5</td><td>是否已准备符合EUDR要求的尽职调查声明（Due Diligence Statement）格式？</td><td></td><td></td><td></td><td></td></tr><tr><td>F3.6</td><td>如涉及小农（Smallholder）收购，是否有将其地块纳入溯源体系的方案？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="模块-f4-环境与用水" tabindex="-1">模块 F4　环境与用水 <a class="header-anchor" href="#模块-f4-环境与用水" aria-label="Permalink to &quot;模块 F4　环境与用水&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>F4.1</td><td>是否持有有效的水资源取用许可证（适用于有取水行为的设施）？</td><td></td><td></td><td></td><td></td></tr><tr><td>F4.2</td><td>是否位于水资源高压力地区（可通过 WRI Aqueduct 核查）？</td><td></td><td></td><td></td><td></td></tr><tr><td>F4.3</td><td>加工厂废水是否经处理后达标排放，并有定期检测记录？</td><td></td><td></td><td></td><td></td></tr><tr><td>F4.4</td><td>农药使用是否符合当地法规，且不使用WHO Class I（极度危险）农药？</td><td></td><td></td><td></td><td></td></tr><tr><td>F4.5</td><td>是否有固体废弃物管理计划，含农业废料（农药包装、有机废料）处置？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="模块-f5-供应链溯源" tabindex="-1">模块 F5　供应链溯源 <a class="header-anchor" href="#模块-f5-供应链溯源" aria-label="Permalink to &quot;模块 F5　供应链溯源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>F5.1</td><td>原料采购是否100%来自已知供应商（无匿名中间商）？</td><td></td><td></td><td></td><td></td></tr><tr><td>F5.2</td><td>是否要求所有原料供应商提供产地证明？</td><td></td><td></td><td></td><td></td></tr><tr><td>F5.3</td><td>是否参与行业溯源平台（如 SourceTrace、Farmforce、Koltiva）？</td><td></td><td></td><td></td><td></td></tr><tr><td>F5.4</td><td>是否有能力区分&quot;身份保留&quot;（Identity Preserved）与&quot;质量保证&quot;（Mass Balance）批次？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><p><strong>授权签署</strong></p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>授权签署人</td><td>__________________</td></tr><tr><td>职务</td><td>__________________</td></tr><tr><td>日期</td><td>__________________</td></tr><tr><td>公章</td><td></td></tr></tbody></table>',24)])])}const u=d(e,[["render",o]]);export{F as __pageData,u as default};
